game.script:
const input = document.querySelector("input");
const network = document.querySelector("network");
const lowerLink = document.querySelector("#lower-link");
const spawnBox = document.querySelector("#spawn-box");
const boostCubes = document.querySelector("#boost-cubes");
const clients = new Map();
const moveKeys = ["KeyW", "KeyA", "KeyS", "KeyD"];
const driveForce = 0.01;
const cubeImpulse = 0.35;
let spawnedBoxes = 0;

function getClientKeys(clientId) {
  let keys = clients.get(clientId);

  if (keys === undefined) {
    keys = new Set();
    clients.set(clientId, keys);
  }

  return keys;
}

function isDown(code) {
  for (const keys of clients.values()) {
    if (keys.has(code)) {
      return true;
    }
  }

  return false;
}

function handleEvent(event) {
  if (event.name === "disconnect") {
    clients.delete(event.clientId);
    return;
  }

  if (event.name === "spawnBox") {
    spawnBoxAtOrigin();
    return;
  }

  if (event.name === "boostCubes") {
    boostAllCubes();
    return;
  }

  if (event.name === "keyPressed") {
    getClientKeys(event.clientId).add(event.data);
    return;
  }

  if (event.name === "keyReleased") {
    getClientKeys(event.clientId).delete(event.data);
  }
}

function spawnBoxAtOrigin() {
  const offset = (spawnedBoxes % 5) * 0.45 - 0.9;

  document.createElement({
    tag: "box",
    class: ["cube"],
    position: [offset, 3.2, 0],
    width: 0.35,
    height: 0.35,
    depth: 0.35,
    color: [0.9, 0.48, 0.18],
    body: "dynamic",
  });
  spawnedBoxes += 1;
}

function boostAllCubes() {
  for (const cube of document.querySelectorAll(".cube")) {
    cube.applyImpulse(0, cubeImpulse, 0);
  }
}

function tickClient() {
  if (spawnBox.wasClicked()) {
    network.emit("spawnBox", null);
  }

  if (boostCubes.wasClicked()) {
    network.emit("boostCubes", null);
  }

  for (const code of moveKeys) {
    if (input.wasPressed(code)) {
      network.emit("keyPressed", code);
    }

    if (input.wasReleased(code)) {
      network.emit("keyReleased", code);
    }
  }
}

function tickServer() {
  let event = network.pollEvent();

  while (event !== undefined) {
    handleEvent(event);
    event = network.pollEvent();
  }

  let forceX = 0;
  let forceZ = 0;

  if (isDown("KeyA")) {
    forceX -= driveForce;
  }
  if (isDown("KeyD")) {
    forceX += driveForce;
  }
  if (isDown("KeyW")) {
    forceZ -= driveForce;
  }
  if (isDown("KeyS")) {
    forceZ += driveForce;
  }

  if (forceX !== 0 || forceZ !== 0) {
    lowerLink.applyImpulseAtPoint(forceX, 0, forceZ, 0, -0.9, 0);
  }
}

function tick() {
  if (input !== null) {
    tickClient();
    return;
  }

  tickServer();
}
